using Microsoft.EntityFrameworkCore;using Microsoft.EntityFrameworkCore.Metadata.Builders;using NutriCasa.Domain.Entities;
namespace NutriCasa.Infrastructure.Persistence.Configurations;
public class BodyMeasurementConfiguration : IEntityTypeConfiguration<BodyMeasurement>{public void Configure(EntityTypeBuilder<BodyMeasurement> builder){builder.ToTable("body_measurements");builder.HasKey(e => e.Id);builder.Property(e => e.Id).HasColumnName("measurement_id").HasDefaultValueSql("uuid_generate_v4()");builder.Property(e => e.WeightKg).HasColumnType("decimal(5,2)");builder.Property(e => e.BodyFatPercentage).HasColumnType("decimal(5,2)");builder.Property(e => e.WaistCm).HasColumnType("decimal(5,2)");builder.Property(e => e.HipCm).HasColumnType("decimal(5,2)");builder.Property(e => e.NeckCm).HasColumnType("decimal(5,2)");builder.Property(e => e.ArmCm).HasColumnType("decimal(5,2)");builder.Property(e => e.ChestCm).HasColumnType("decimal(5,2)");builder.Property(e => e.ThighCm).HasColumnType("decimal(5,2)");builder.HasOne(e => e.User).WithMany().HasForeignKey(e => e.UserId).OnDelete(DeleteBehavior.Cascade);builder.HasIndex(e => new { e.UserId, e.MeasuredAt });}}
